inline function onButtonBandControl(component, value)
{
	local index = grpBtns.indexOf(component);
	local attributes = [ScriptFX1.lows, ScriptFX1.mids, ScriptFX1.highs];

	// If a button is clicked > solo the selected band
	if(value)
	{
		for(i = 0; i < grpBtns.length; i++)
		{
			ScriptFX1.setAttribute(attributes[i], i == index && value);
			grpBtns[i].setValue(i == index && value);
		}
	}
	// If no button is clicked > enable all bands
	else
	{
		for(i = 0; i < grpBtns.length; i++)
			ScriptFX1.setAttribute(attributes[i], !value);
	}
}

