// change this for every project
const var PITCH_INDEXES = ["a", "b", "c"]; 
const var PITCH_TARGET_INDEXES = [[1], [2, 3, 4], [5, 6]];

// This will hold a list of all knobs
const var pitchKnobs = [];

// This will hold a 2D-array of all targets (so that the index of the knob can be connected to multiple targets)
const var pitchTargets = [];

// One callback to rule them all
inline function onPitchKnob(component, value)
{
	// get the index from the list
	local idx = pitchKnobs.indexOf(component);

	// set all targets in the target list for the given index
	for(t in pitchTargets[idx])
		t.setIntensity(value);
}

// This function will create the two arrays used in the callback
inline function init()
{
	for(i = 0; i < PITCH_INDEXES.length; i++)
	{
		pitchKnobs.push(Content.getComponent("Pitch_" + PITCH_INDEXES[i]));
		pitchKnobs[i].setControlCallback(onPitchKnob);

		local targets = [];

		for(p in PITCH_TARGET_INDEXES[i])
			targets.push(Synth.getModulator("Constant" + p));

		pitchTargets.push(targets);
	}
}

init();

