tabLAF.registerFunction("drawToggleButton", function(g, obj)
{
	var a = obj.area;
	var p = Content.createPath();

	p.startNewSubPath(TWO_R, 0);
	p.lineTo(a[2] - TWO_R, 0);
	p.quadraticTo(a[2] - R, 0, a[2] - R, R);

	if (obj.value)
	{
		p.lineTo(a[2] - R, a[3] - R);
		p.quadraticTo(a[2] - R, a[3], a[2], a[3]);
		p.lineTo(0, a[3]);
		p.quadraticTo(R, a[3], R, a[3] - R);
	}
	else
	{
		p.lineTo(a[2] - R, a[3]);
		p.lineTo(a[2], a[3]);
		p.lineTo(0, a[3]);
		p.lineTo(R, a[3]);
	}

	p.lineTo(R, R);
	p.quadraticTo(R, 0, TWO_R, 0);

	g.setColour(obj.value ? obj.bgColour : 0xFF808080);
	g.fillPath(p, a);

	g.setColour(obj.value ? obj.itemColour2 : obj.textColour);
	g.drawAlignedText(obj.text, obj.area, "centred");
