const KnbLaf = Content.createLocalLookAndFeel();

KnbLaf.registerFunction("drawRotarySlider", function(g, obj)
{
	//Console.print(trace(obj));
	g.fillAll(obj.bgColour);

	reg a = obj.area;
	reg speed = 10;
	reg ani = !isDefined(ani) ? 0 : ani;
	reg comp = Content.getComponent(obj.id);
	reg t = !isDefined(t) ? Engine.createTimerObject() : t;
	reg inc = !isDefined(inc) ? true : inc;
	reg state = !isDefined(state) ? "xinc" : state;
	reg xy = !isDefined(xy) ? [0, 0, 0, 0] : xy;

	if (obj.hover)
	{
		t.setTimerCallback(function()
		{
			switch (state)
			{
				case "xinc":
					ani = ani+speed;
					xy = [ani, 0];

					if (ani+speed > a[2])
					{
						state = "yinc";
						ani = 0;
						xy = [a[2], ani];
					}
					break;

				case "yinc":
					ani = ani+speed;
					xy = [a[2], ani];

					if ((ani+speed) % a[3] == 0)
					{
						state = "xdec";
						ani = a[2];
						xy = [ani, a[3]];
					}
					break;

				case "xdec":
					ani = ani-speed;
					xy = [ani, a[3]];

					if (ani-speed < 0)
					{
						state = "ydec";
						ani = a[3];
						xy = [0, ani];
					}
					break;

				case "ydec":
					ani = ani-speed;
					xy = [0, ani];

					if (ani-speed < 0)
					{
						state = "xinc";
						ani = 0;
						xy = [ani, 0];
					}
					break;
			}
			comp.sendRepaintMessage();
		});

		t.startTimer(30);
		g.setColour(obj.itemColour1);
		g.fillEllipse([xy[0]-6, xy[1]-6, 12, 12]);
	}

	if (!obj.hover)
	{
		ani = undefined;
		inc = true;
		t.stopTimer();
	}
});


