const var Speed = Content.getComponent("Speed");
const var Degrees = Content.getComponent("Degrees");
const var Blur = Content.getComponent("Blur");
const var Width = Content.getComponent("Width");



const KnbLaf = Content.createLocalLookAndFeel();

KnbLaf.registerFunction("drawRotarySlider", function(g, obj)
{
	reg a = obj.area;
	reg comp = Content.getComponent(obj.id);
	reg t = !isDefined(t) ? Engine.createTimerObject() : t;
	reg count = !isDefined(count) ? 0 : count;
	reg done = !isDefined(done) ? false : done;
	var w = Width.getValue();

	if (obj.hover)
	{
		t.setTimerCallback(function()
		{
			count = parseInt(t.getMilliSecondsSinceCounterReset() / (12-Speed.getValue()));

			if (count > Degrees.getValue())
			{
				done = true;
				count = 0;
				t.stopTimer();
			}

			comp.sendRepaintMessage();
		});

		if (!t.isTimerRunning() && !done)
			t.startTimer(30);
	}

	if (!obj.hover)
	{
		count = 0;
		done = undefined;
		t.stopTimer();
	}

	g.beginLayer(false);

	//	Animation
	if (count > 0)
	{
		g.rotate(Math.toRadians(count), [a[2]/2, a[3]/2]);
		g.setColour(Colours.white);
		g.fillRoundedRectangle([a[2]/2-w, -a[3], w*2, a[3]*3], 2);
	}
	g.rotate(Math.toRadians(-count), [a[2]/2, a[3]/2]);
	g.gaussianBlur(Blur.getValue());
	g.endLayer();

	//	Rectangle
	g.setColour(obj.bgColour);
	g.fillRoundedRectangle([2, 2, a[2]-4, a[3]-4], 6);

	//	Object text
	g.setFont("default", a[3]/3);
	g.setColour(Colours.withAlpha(obj.textColour, 0.3));
	g.drawAlignedText(obj.text, a, "centred");

	//	Handle
	g.setColour(obj.itemColour2);
	g.fillRoundedRectangle([(a[2]-4)*obj.valueNormalized, 6, 5, a[3]-12], 2);

	//	Value
	g.setFont("default", 13);
	g.setColour(Colours.withAlpha(obj.textColour, 0.7));
	g.drawAlignedText(obj.valueAsText, [0, 6, a[2], a[3]-12], "centredTop");
});


