reg STATE = 0;
Knob1TimerPnl.setTimerCallback(function()
{
	if (STATE == 0)
	{
		functTwo();
		STATE = 1;
		this.startTimer(50);
	}

	else
	{
		functThree();
		STATE = 0;
		Knob1TimerPnl.data.isRunning = undefined;
		this.stopTimer();
	}
});

const var Knob1 = Content.getComponent("Knob1");

inline function onKnob1Control(component, value)
{
	if (isDefined(Knob1TimerPnl.data.isRunning))
		return;

	else
	{
		functOne();
		Knob1TimerPnl.startTimer(30);
		Knob1TimerPnl.data.isRunning = true;
	}
	/*	
	1. Firstly run functOne()
	2. Then wait for 30 ms and run functTwo()
	3. Then wait for 50 ms and run functThree()	
	*/
};

