inline function functOne()
{	
	local index_One_Gain = ParaEQ.BandOffset * 1 + ParaEQ.Gain;
	local index_Three_Gain = ParaEQ.BandOffset * 3 + ParaEQ.Gain;

	ParaEQ.setAttribute(index_One_Gain, 13.6 * Knob1.getValue());
	ParaEQ.setAttribute(index_Three_Gain, -10.9 * Knob1.getValue());	
	Reverberate.setAttribute(Reverberate.RoomSize, 0.95 - 0.2 * Knob1.getValue());

	Console.print("function 1");
}



inline function functTwo()
{
	local index_One_Freq = ParaEQ.BandOffset * 1 + ParaEQ.Freq;
	local index_Three_Freq = ParaEQ.BandOffset * 3 + ParaEQ.Freq;

	ParaEQ.setAttribute(index_One_Freq, 100 + 1200 * Knob1.getValue());
	ParaEQ.setAttribute(index_Three_Freq, 500 - 400 * Knob1.getValue());	
	SimpleGainer.setAttribute(SimpleGainer.Width, 100 + 50 * Knob1.getValue());	
	Reverberate.setAttribute(Reverberate.Damping, 1.0 - 0.5 * Knob1.getValue());

	Console.print("function 2");	
}



inline function functThree()
{
	SimpleGainer.setAttribute(SimpleGainer.Gain, 0 + 2.3 * Knob1.getValue());	

	local index_One_Q = ParaEQ.BandOffset * 1 + ParaEQ.Q;
	local index_Three_Q = ParaEQ.BandOffset * 3 + ParaEQ.Q;

	ParaEQ.setAttribute(index_One_Q, 1.0 - 0.34 * Knob1.getValue());
	ParaEQ.setAttribute(index_Three_Q, 1 + 2.5 * Knob1.getValue());

	Console.print("function 3");
}

