//	TABLE W GRID FACTORY (name, x, y, width, height, number of snaps)
inline function createTableWithGrid(name, x, y, w, h, numsnaps)
{
	local container = Content.addPanel(name+"Container", x, y);
	Content.setPropertiesFromJSON(name+"Container",
	{
		"type": "ScriptPanel",
		"id": name+"Container",
		"x": x,
		"y": y,
		"width": w,
		"height": h,
		"bgColour": 16777215,
		"itemColour": 0,
		"itemColour2": 0,
		"textColour": 16777215,
	});

	local grid = Content.addPanel(name+"Grid");
	Content.setPropertiesFromJSON(name+"Grid",
	{
		"type": "ScriptPanel",
		"id": name+"Grid",
		"x": 0,
		"y": 0,
		"width": w,
		"height": h,
		"parentComponent": name+"Container"
	});

	local table = Content.addTable(name);
	Content.setPropertiesFromJSON(name,
	{
		"type": "ScriptTable",
		"id": name,
		"x": 0,
		"y": 0,
		"width": w,
		"height": h,
		"saveInPreset": true,
		"parentComponent": name+"Container"
	});

	local values = [];
	local snap = 1/numsnaps;

	for (i = 0; i < numsnaps; i++)
		values.push(snap * i);

	values.push(1.0);

	table.setSnapValues(values);
	grid.setValue(values);
	grid.changed();

	grid.setPaintRoutine(function(g)
	{
		g.setColour(Colours.chartreuse);

		if (typeof this.getValue() == "object")
		{
			var space = this.getWidth() / (this.getValue().length-1);

			for (j = 0; j <= this.getValue().length; j++)
				g.drawLine(j * space, j * space, 4, this.getHeight()-4, 0.2);
		}
	});
}

