const var Panel1 = Content.getComponent("Panel1");

const var outer = 250;
const var inner = 200;

Panel1.setPaintRoutine(function(g)
{
	g.fillAll(Colours.black);

	g.setColour(this.data.isValid ? Colours.green : Colours.darkred);
	g.fillEllipse([(this.getWidth()-outer)/2.0, (this.getHeight()-outer)/2.0, outer, outer]);
	g.setColour(Colours.black);
	g.fillEllipse([(this.getWidth()-inner)/2.0, (this.getHeight()-inner)/2.0, inner, inner]);
});


Panel1.setMouseCallback(function(event)
{
	var posX = event.x - this.getWidth()/2.0;
	var posY = event.y - this.getHeight()/2.0;

	var l = Math.sqrt((posX*posX) + (posY*posY));

	this.data.isValid = l < outer/2.0 && l > inner/2.0;
	this.repaint();
});

